#include <stdio.h>
#include <string.h>

int isAnagram(const char *s, const char *t) {
    int cnt[26] = {0};
    for (size_t i = 0; s[i]; ++i) cnt[s[i] - 'a']++;
    for (size_t i = 0; t[i]; ++i) cnt[t[i] - 'a']--;
    for (int i = 0; i < 26; ++i) if (cnt[i] != 0) return 0;
    return 1;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char s[50001], t[50001];
    while (T--) {
        if (!fgets(s, sizeof(s), stdin)) break;
        s[strcspn(s, "\n")] = '\0';
        if (!fgets(t, sizeof(t), stdin)) break;
        t[strcspn(t, "\n")] = '\0';
        if (strlen(s) != strlen(t)) {
            printf("NO\n");
            continue;
        }
        printf(isAnagram(s, t) ? "YES\n" : "NO\n");
    }
    return 0;
}

