import java.io.*;
import java.util.*;

public class Main {
    private static boolean isAnagram(String s, String t) {
        if (s.length() != t.length()) return false;
        int[] cnt = new int[26];
        for (int i = 0; i < s.length(); i++) cnt[s.charAt(i) - 'a']++;
        for (int i = 0; i < t.length(); i++) cnt[t.charAt(i) - 'a']--;
        for (int v : cnt) if (v != 0) return false;
        return true;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String s = br.readLine();
            String t = br.readLine();
            out.append(isAnagram(s, t) ? "YES" : "NO");
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def is_anagram(s: str, t: str) -> bool:
    if len(s) != len(t):
        return False
    cnt = [0] * 26
    for ch in s:
        cnt[ord(ch) - 97] += 1
    for ch in t:
        cnt[ord(ch) - 97] -= 1
    return all(c == 0 for c in cnt)

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(T):
        s = data[idx].strip(); idx += 1
        t = data[idx].strip(); idx += 1
        out.append('YES' if is_anagram(s, t) else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

